package com.knf.dev.librarymanagementsystem.controller;

import java.util.List;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Controller;
import org.springframework.ui.ModelMap;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.servlet.ModelAndView;

import com.knf.dev.librarymanagementsystem.model.Book;
import com.knf.dev.librarymanagementsystem.service.BookService;

@Controller
public class BookController {

	@Autowired
	private BookService bookService;

	@GetMapping("/books")
	public ModelAndView listBooks(ModelMap model) {
		List<Book> books = bookService.listAll();
		model.addAttribute("books", books);
		return new ModelAndView("book/list", "model", model);
	}

	@RequestMapping("/book/{id}")
	public String showBook(@PathVariable Integer id, ModelMap model) {
		Book book = bookService.get(id);
		model.addAttribute("book", book);
		return "book/show";
	}

	@GetMapping("/addBook")
	public String addBook(ModelMap model) {
		Book book = new Book();
		model.addAttribute("book", book);
		return "book/add";
	}

	@PostMapping("/saveBook")
	public String saveBook(Book book, ModelMap model) {
		bookService.saveOrUpdate(book);
		return "redirect:/books";
	}

	@GetMapping("/editBook/{id}")
	public ModelAndView editBook(@PathVariable Integer id) {
		ModelAndView mav = new ModelAndView("book/add");
		Book book = bookService.get(id);
		mav.addObject("book", book);
		return mav;
	}

	@GetMapping("/deleteBook/{id}")
	public String deleteBook(@PathVariable Integer id) {
		bookService.delete(id);
		return "redirect:/books";
	}
}


