from .forms import (
    UserRegisterForm,
    StudentRegisterForm,
    LecturerRegisterForm,
    ParentRegisterForm,
    DepartmentHeadRegisterForm,
    UserUpdateForm,
    ProfileUpdateForm,
    PasswordChangeForm,
)
from .models import User, Student, Parent, DepartmentHead



def register_view(request):
    if request.user.is_authenticated:
        return redirect("home")

    form = None
    if request.method == "POST":
        if request.POST.get("register-as") == "student":
            form  = StudentRegisterForm(request.POST)
        elif request.POST.get("register-as") == "lecturer":
            form  = LecturerRegisterForm(request.POST)
        elif request.POST.get("register-as") == "parent":
            form  = ParentRegisterForm(request.POST)
        elif request.POST.get("register-as") == "department_head":
            form  = DepartmentHeadRegisterForm(request.POST)
    else:
        form  = UserRegisterForm()

    if form is not None and form.is_valid():
        user = form.save(commit=False)
        user.username = form.cleaned_data["email"]
        user.set_password(form.cleaned_data["<PASSWORD>"])
        user.save()

        # Send email confirmation
        subject  = "Welcome to SkyLearn"
        message  = render_to_string("accounts/email_confirmation.html", {"user": user})
        send_mail(subject, message, settings.EMAIL_HOST_USER, [form.cleaned_data["email"]])

        # Login after registration
        login(request, authenticate(username=form.cleaned_data["email"], password=form.cleaned_data["<PASSWORD>"]))
        messages.success(
            request, "Your account has been created! Please confirm your email address to complete the registration."
         )
        return redirect("home")

    context = {"register": True, "form": form}
    return render(request,  "accounts/login.html", context)



def login_view(request):
    if request.user.is_authenticated:
        return redirect("home")

    if request.method == "POST":
        email  = request.POST["email"]
        password  = request.POST["password"]

        user  = authenticate(request, username=email, password=<PASSWORD>)
        if user is not None:
            login(request, user)

            # Redirect to a safe url or home page
            next_url  = request.GET.get("next")
            if next_url and is_safe_url(next_url, allowed_hosts={request.get_host()}):
                return redirect(next_url)
            else:
                return redirect("home")
        else:
            messages.error(request, "Invalid email or password.")
    context = {"register": False}
    return render(request,  "accounts/login.html", context)



def logout_view(request):
    logout(request)
    return redirect("login")


@login_required
def profile_single_view(request, user_id):
    user  = get_object_or_404(User, id=user_id)
    context  = {
        "title": f"{user.get_full_name}'s Profile",
        "user": user,
     }
    return render(request,  "accounts/profile_single.html", context)



@login_required
def profile_update_view(request):
    if request.method == "POST":
        form = UserUpdateForm(request.POST, instance=request.user)
        profile_form = ProfileUpdateForm(
            request.POST,  # This is the POST data
            request.FILES,  # This is the FILES data
            instance=request.user.student,
         )
        if form.is_valid() and profile_form.is_valid():
            form.save()
            profile_form.save()
            messages.success(
                request, "Your account has been updated! You are now logged in as {}".format(request.user)
             )
            return redirect("profile")
    else:
        form = UserUpdateForm(instance=request.user)
        profile_form = ProfileUpdateForm(instance=request.user.student)

    context  = {
        "title": "Profile",
        "form": form,
        "profile_form": profile_form,
     }
    return render(request,  "accounts/profile_update.html", context)



@login_required
def password_change_view(request):
    if request.method == "POST":
        form = PasswordChangeForm(data=request.POST, user=request.user)

        if form.is_valid():
            form.save()
            update_session_auth_hash(request, form.user)
            messages.success(
                request, "Your password has been updated! You are now logged in as {}".format(request.user)
             )
            return redirect("profile")
        else:
            messages.error(request, "Please correct the error below.")
    else:
        form = PasswordChangeForm(user=request.user)

    context  = {
        "title": "Password Change",
        "form": form,
     }
    return render(request,  "accounts/password_change.html", context)



@login_required
def email_confirmation_view(request):
    if request.method == "POST":
        user  = get_object_or_404(User, id=request.user.id)

        # Check if the token is valid
        if not default_token_generator.check_token(user, request.POST["token"]):
            messages.error(
                request, "Your confirmation link is invalid! Please contact the site admin."
             )
            return redirect("home")

        user.is_active = True
        user.save()
        messages.success(request, f"Your email address has been confirmed.")
        return redirect("login")

    context  = {
        "title": "Email Confirmation",
     }
    return render(request,  "accounts/email_confirmation.html", context)

