from django import forms
from django.contrib.auth.models import User
from django.core.validators import RegexValidator
from django.utils.translation import gettext_lazy as _
from django.conf import settings

from .models import (
    Student,
    Parent,
    DepartmentHead,
    GENDERS,
    RELATION_SHIP,
)



class UserRegisterForm(forms.ModelForm):
    email = forms.EmailField()

    class Meta:
        model  = User
        fields  = ("email", "password")


class StudentRegisterForm(UserRegisterForm):
    first_name = forms.CharField(max_length=120)
    last_name = forms.CharField(max_length=120)
    gender = forms.ChoiceField(choices=GENDERS, required=True)

    class Meta:
        model  = User
        fields  = ("email", "password") + User._meta.get_fields()[3:]


class LecturerRegisterForm(UserRegisterForm):
    first_name = forms.CharField(max_length=120)
    last_name = forms.CharField(max_length=120)

    class Meta:
        model  = User
        fields  = ("email", "password") + User._meta.get_fields()[3:]


class ParentRegisterForm(UserRegisterForm):
    first_name = forms.CharField(max_length=120)
    last_name = forms.CharField(max_length=120)

    class Meta:
        model  = User
        fields  = ("email", "password") + User._meta.get_fields()[3:]


class DepartmentHeadRegisterForm(UserRegisterForm):
    first_name = forms.CharField(max_length=120)
    last_name = forms.CharField(max_length=120)

    class Meta:
        model  = User
        fields  = ("email", "password") + User._meta.get_fields()[3:]


class UserUpdateForm(forms.ModelForm):
    email = forms.EmailField()

    class Meta:
        model  = User
        fields  = ("first_name", "last_name", "email")



class ProfileUpdateForm(forms.ModelForm):
    gender = forms.ChoiceField(choices=GENDERS, required=True)

    class Meta:
        model  = Student
        fields  = ("level", "program", "gender")


class PasswordChangeForm(forms.ModelForm):
    password = forms.CharField(widget=forms.PasswordInput())
    confirm_password = forms.CharField(label="Confirm Password", widget=forms.PasswordInput())

    class Meta:
        model  = User
        fields  = ("password",)

    def clean_confirm_password(self):
        data  = self.cleaned_data["password"]
        confirm_password  = self.cleaned_data["confirm_password"]

        if data != confirm_password:
            raise forms.ValidationError("Passwords must match.")
        return confirm_password


class ParentUpdateForm(forms.ModelForm):
    first_name = forms.CharField(max_length=120)
    last_name = forms.CharField(max_length=120)

    class Meta:
        model  = Parent
        fields  = ("first_name", "last_name")


class DepartmentHeadUpdateForm(forms.ModelForm):
    first_name = forms.CharField(max_length=120)
    last_name = forms.CharField(max_length=120)

    class Meta:
        model  = DepartmentHead
        fields  = ("first_name", "last_name")

