from django.forms import ModelForm, TextInput, SelectDateWidget, DateField

from .models import NewsAndEvents, Session, Semester


class NewsAndEventsForm(ModelForm):
    class Meta:
        model = NewsAndEvents
        fields  = [
            "title",
