@login_required
def course_registration(request):
    student  = get_object_or_404(Student, student__pk=request.user.id)

    courses  = CourseAllocation.objects.filter(lecturer__pk=request.user.id).values("course")
    t  = TakenCourse.objects.filter(student=student).values("course")

    no_course_is_registered  = False   # Check if no course is registered
    all_courses_are_registered  = False

    registered_courses  = CourseAllocation.objects.filter(lecturer__pk=request.user.id, course__in=t)
    if (
        registered_courses.count() == 0
     ):   # Check if number of registered courses is 0
        no_course_is_registered  = True

    if registered_courses.count() == CourseAllocation.objects.filter(lecturer__pk=request.user.id).count():
        all_courses_are_registered  = True

    total_first_semester_credit  = 0
    total_sec_semester_credit  = 0
    total_registered_credit  = 0
    for i in courses:
        if i["course__semester"] == "First":
            total_first_semester_credit  += int(i["course__credit"])
        if i["course__semester"] == "Second":
            total_sec_semester_credit  += int(i["course__credit"])
    for i in registered_courses:
        total_registered_credit  += int(i.course.credit)

    context  = {
        "is_calender_on": True,
        "all_courses_are_registered": all_courses_are_registered,
        "no_course_is_registered": no_course_is_registered,
        "current_semester": current_semester,
        "courses": courses,
        "total_first_semester_credit": total_first_semester_credit,
        "total_sec_semester_credit": total_sec_semester_credit,
        "registered_courses": registered_courses,
        "total_registered_credit": total_registered_credit,
        "student": student,
    }

    return render(request, "course/course_registration.html", context)



@login_required
def course_drop(request):
    if request.method == "POST":
        student  = get_object_or_404(Student, student__pk=request.user.id)
        course_ids  = request.POST.getlist("course_ids")
        print("course_ids", course_ids)
        for course_id in course_ids:
            course  = get_object_or_404(Course, pk=course_id)
            TakenCourse.objects.filter(student=student, course=course).delete()
        messages.success(request, "Courses dropped successfully!")
        return redirect("course_registration")



