class MCQuestionFormSet(forms.models.BaseInlineFormSet):
    def clean(self):
        super().clean()

        # Check for duplicate questions
        if any(self.errors):
            return

        ids = []
        for form in self.forms:
            if not form.is_valid():
                continue

            id = form.cleaned_data["id"]
            if id and id in ids:
                raise forms.ValidationError(_("You can't have two questions with the same ID"))
            ids.append(id)

        # Check for duplicate choices
        for question in self.instance:
            choices = [choice.choice_text for choice in question.get_choices()]
            duplicates = set([x for x in choices if choices.count(x) > 1])
            if len(duplicates):
                raise forms.ValidationError(_("You can't have two choices with the same text"))


