    Question,
)



class QuizAddForm(forms.ModelForm):
    class Meta:
        model = Quiz
        fields  = ("title", "description", "category")


class QuestionForm(forms.ModelForm):
    content = forms.CharField(widget=forms.Textarea())

    class Meta:
        model = Question
        fields = ["content"]



class MCQuestionFormSet(forms.models.BaseInlineFormSet):
    def clean(self):
        if any(self.errors):
            return

        num_choices  = sum([
            1 for form in self._forms if form.cleaned_data["DELETE"] is False
        ])
        if not num_choices >= 2:
            raise ValidationError(_("You must create at least two choices."))


class MCQuestionForm(forms.ModelForm):
    class Meta:
        model = MCQuestion
        fields = ["content", "explanation", "choice_order"]

    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)

        if self.instance and self.instance.pk:
            self._choices  = Choice.objects.filter(question=self.instance)
            for choice in self._choices:
                self.fields[f"choice_{choice.id}"]  = forms.BooleanField(
                    label=choice, initial=choice.correct
                )

    def clean_content(self):
        return self.cleaned_data["content"].strip()

    def save(self, commit=True):
        question  = super().save(commit=False)

        if not question.pk:
            question.quiz  = self._quiz

        if commit:
            question.save()

            for choice in self._choices:
                choice.delete()

            for form in self._forms:
                if form.cleaned_data["DELETE"]:
                    continue

                choice, created  = Choice.objects.get_or_create(
                    id=form.cleaned_data["id"], question=question
                )
                choice.choice_text  = form.cleaned_data["choice_text"]
                choice.correct  = form.cleaned_data["correct"]
                if commit:
                    choice.save()

        return question


class EssayForm(forms.ModelForm):
    class Meta:
        model = EssayQuestion
        fields = ["content", "explanation"]

    def clean_content(self):
        return self.cleaned_data["content"].strip()



