    form  = QuizAdminForm

    list_display  = ("title", "category")
    prepopulated_fields  = {"slug": ("title",)}



class QuestionAdmin(admin.ModelAdmin):
    list_filter  = ("quiz__course",)


class MCQuestionAdmin(QuestionAdmin):
    formset  = MCQuestionFormSet

    def get_formsets_with_inlines(self, request, obj=None):
        for inline in self._get_inline_instances(request, obj):
            if isinstance(inline, admin.StackedInline) or isinstance(
                inline, admin.TabularInline
            ):
                yield inline.get_formset(request, obj), inline

    def get_formsets(self, request, obj=None):
        for formset in self.get_formsets_with_inlines(request, obj):
            yield formset


class EssayQuestionAdmin(QuestionAdmin):
    pass



admin.site.register(Quiz, QuizAdmin)
admin.site.register(MCQuestion, MCQuestionAdmin)
admin.site.register(EssayQuestion, EssayQuestionAdmin)
admin.site.register(Choice)
admin.site.register(Sitting)


