        fields = ["content", "explanation"]


class MCQuestionFormSet(forms.models.BaseInlineFormSet):
    def clean(self):
        if any(self.errors):
            return

        for form in self._forms:
            if not form.is_valid():
                continue

            if form.cleaned_data["DELETE"]:
                continue

            if (
                Question.objects.filter(
                    Q(quiz=self.instance) & ~Q(id=form.instance.id),
                    content=form.cleaned_data["content"],
                )
                .exists()
            ):
                raise ValidationError(_("Duplicate question"))


class QuizMarkingList(forms.Form):
    quiz = forms.ModelChoiceField(queryset=Quiz.objects.all())

    def __init__(self, *args, **kwargs):
        self.request = kwargs.pop("request")
        super().__init__(*args, **kwargs)

        if not self.request.user.is_superuser:
            self.fields["quiz"].queryset  = Quiz.objects.filter(
                Q(course__lecturer=self.request.user) | Q(course__students=self.request.user)
            )


