        self.slug  = kwargs["slug"]
        super().__init__(*args, **kwargs)

    def clean(self):
        if not self.request.user.is_authenticated:
            raise ValidationError(_("You must be logged in to take a quiz"))

        if Sitting.objects.filter(quiz=self.quiz, user=self.request.user).exists():
            raise ValidationError(_("You have already taken this quiz"))


class QuizMarkingForm(forms.ModelForm):
    def __init__(self, *args, **kwargs):
