                .andExpect(jsonPath("$[0].totalCopies").value(2))
                .andExpect(jsonPath("$[0].availableCopies").value(2));
    }

    @Test
    void create() throws Exception{
        var request: MockHttpServletRequestBuilder = post("/api/books")
                .contentType(MediaType.APPLICATION_JSON)
                .content("{\"isbn\":\"978-3-16-148410-0\",\"title\":\"Java 9 for Professional Developers\",\"author\":\"<NAME>\",\"totalCopies\":2,\"availableCopies\":2}");

        mockMvc.perform(request)
