                .andDo(print())
                .andExpect(status().isOk())
                .andExpect(jsonPath("$", hasSize(1)))
                .andExpect(jsonPath("$[0].id").value(1))
                .andExpect(jsonPath("$[0].isbn").value("978-3-16-148410-0"))
                .andExpect(jsonPath("$[0].title").value("Java 9 for Professional Developers"))
                .andExpect(jsonPath("$[0].author").value("<NAME>"))
                .andExpect(jsonPath("$[0].totalCopies").value(2))
                .andExpect(jsonPath("$[0].availableCopies").value(2));
