package org.engripaye.librarymanagementsystem.service;

import lombok.AllArgsConstructor;
import org.engripaye.librarymanagementsystem.model.Book;
import org.engripaye.librarymanagementsystem.model.Borrowing;
import org.engripaye.librarymanagementsystem.repository.BookRepository;
import org.engripaye.librarymanagementsystem.repository.BorrowingRepository;
import org.springframework.stereotype.Service;

@Service
@AllArgsConstructor
public class BorrowingService {

    private final BookRepository bookRepository;
    private final BorrowingRepository borrowingRepository;


    public void borrow(Long bookId, Long userId){
        var book = bookRepository.findById(bookId);
        if(book == null) throw new RuntimeException("Book not found");

        var user = UserRepository.findById(userId);
        if(user == null) throw new RuntimeException("User not found");

        if(book.getAvailableCopies()  <= 0){
            throw new RuntimeException("No copies available for borrowing");
        }

        book.setAvailableCopies(book.getAvailableCopies() -1 );
        bookRepository.save(book);

        var borrowing = new Borrowing();
        borrowing.setBook(book);
        borrowing.setUser(user);
        borrowing.setBorrowedDate(LocalDate.now());
        borrowingRepository.save(borrowing);
    }

    public void returnBook(Long bookId, Long userId){
        var book = bookRepository.findById(bookId);
        if(book == null) throw new RuntimeException("Book not found");

        var user = UserRepository.findById(userId);
        if(user == null) throw new RuntimeException("User not found");

        var borrowing = borrowingRepository.findByBookAndUser(book, user);
        if(borrowing == null){
            throw new RuntimeException("Borrowing record not found");
        }

        book.setAvailableCopies(book.getAvailableCopies() +1 );
        bookRepository.save(book);

        borrowing.setReturnedDate(LocalDate.now());
        borrowingRepository.save(borrowing);
    }
}

