package org.engripaye.librarymanagementsystem.controller;

import lombok.AllArgsConstructor;
import org.engripaye.librarymanagementsystem.service.BorrowingService;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/borrow")
@AllArgsConstructor
public class BorrowingController {

    private final BorrowingService service;


    @PostMapping("/{bookId}/user/{userId}")
    public void borrow(@PathVariable Long bookId, @PathVariable Long userId){
